#include "temp_control_mixed_u_ros_microros_pkg/base_headers/tcp_tempControl_base_src.h"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

// Forward declarations of user compute entry points
void tcp_tempControl_handle_tempChanged(tcp_tempControl_base_t * self);
void tcp_tempControl_handle_fanAck(tcp_tempControl_base_t * self, const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__FanAck * msg);
void tcp_tempControl_handle_setPoint(tcp_tempControl_base_t * self, const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__SetPoint * msg);

// Static instance pointer for subscription callback context (heap-free, MCU-compatible)
static tcp_tempControl_base_t * g_self = NULL;

//=================================================
//  S u b s c r i p t i o n   C a l l b a c k s
//=================================================

static void tcp_tempControl_currentTemp_subscription_callback(const void * msgin)
{
    const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__Temperature * msg = (const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__Temperature *) msgin;
    if (g_self != NULL) {
        g_self->tcp_tempControl_currentTemp_msg = *msg;
    }
}

static void tcp_tempControl_tempChanged_subscription_callback(const void * msgin)
{
    (void)msgin;
    if (g_self != NULL) {
        tcp_tempControl_handle_tempChanged(g_self);
    }
}

static void tcp_tempControl_fanAck_subscription_callback(const void * msgin)
{
    const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__FanAck * msg = (const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__FanAck *) msgin;
    if (g_self != NULL) {
        tcp_tempControl_handle_fanAck(g_self, msg);
    }
}

static void tcp_tempControl_setPoint_subscription_callback(const void * msgin)
{
    const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__SetPoint * msg = (const temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__SetPoint *) msgin;
    if (g_self != NULL) {
        tcp_tempControl_handle_setPoint(g_self, msg);
    }
}

//=================================================
//  I n i t i a l i z a t i o n
//=================================================

void tcp_tempControl_base_init(tcp_tempControl_base_t * self)
{
    g_self = self;

    self->allocator = rcl_get_default_allocator();

    rclc_support_init(&self->support, 0, NULL, &self->allocator);

    rclc_node_init_default(&self->node, "tcp_tempControl", "", &self->support);

    // Setting up connections
    rclc_publisher_init_default(
        &self->tcp_tempControl_fanCmd_publisher,
        &self->node,
        ROSIDL_GET_MSG_TYPE_SUPPORT(temp_control_mixed_u_ros_cpp_pkg_interfaces, msg, FanCmd),
        "tcp_fan_fanCmd");

    // Setting up subscriptions
    rclc_subscription_init_default(
        &self->tcp_tempControl_currentTemp_subscription,
        &self->node,
        ROSIDL_GET_MSG_TYPE_SUPPORT(temp_control_mixed_u_ros_cpp_pkg_interfaces, msg, Temperature),
        "tcp_tempControl_currentTemp");

    rclc_subscription_init_default(
        &self->tcp_tempControl_tempChanged_subscription,
        &self->node,
        ROSIDL_GET_MSG_TYPE_SUPPORT(temp_control_mixed_u_ros_cpp_pkg_interfaces, msg, Empty),
        "tcp_tempControl_tempChanged");

    rclc_subscription_init_default(
        &self->tcp_tempControl_fanAck_subscription,
        &self->node,
        ROSIDL_GET_MSG_TYPE_SUPPORT(temp_control_mixed_u_ros_cpp_pkg_interfaces, msg, FanAck),
        "tcp_tempControl_fanAck");

    rclc_subscription_init_default(
        &self->tcp_tempControl_setPoint_subscription,
        &self->node,
        ROSIDL_GET_MSG_TYPE_SUPPORT(temp_control_mixed_u_ros_cpp_pkg_interfaces, msg, SetPoint),
        "tcp_tempControl_setPoint");

    rclc_executor_init(&self->executor, &self->support.context, 4, &self->allocator);
    rclc_executor_add_subscription(&self->executor, &self->tcp_tempControl_currentTemp_subscription, &self->tcp_tempControl_currentTemp_msg, tcp_tempControl_currentTemp_subscription_callback, ON_NEW_DATA);
    rclc_executor_add_subscription(&self->executor, &self->tcp_tempControl_tempChanged_subscription, &self->tcp_tempControl_tempChanged_msg, tcp_tempControl_tempChanged_subscription_callback, ON_NEW_DATA);
    rclc_executor_add_subscription(&self->executor, &self->tcp_tempControl_fanAck_subscription, &self->tcp_tempControl_fanAck_msg, tcp_tempControl_fanAck_subscription_callback, ON_NEW_DATA);
    rclc_executor_add_subscription(&self->executor, &self->tcp_tempControl_setPoint_subscription, &self->tcp_tempControl_setPoint_msg, tcp_tempControl_setPoint_subscription_callback, ON_NEW_DATA);
}

void tcp_tempControl_base_spin(tcp_tempControl_base_t * self)
{
    rclc_executor_spin(&self->executor);
}

//=================================================
//  C o m m u n i c a t i o n
//=================================================

void put_fanCmd(tcp_tempControl_base_t * self, temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__FanCmd * msg)
{
    rcl_ret_t ret = rcl_publish(&self->tcp_tempControl_fanCmd_publisher, msg, NULL);
    if (ret != RCL_RET_OK) {
        PRINT_ERROR("Failed to publish fanCmd");
    }
}

//=================================================
//  D a t a   P o r t   A c c e s s
//=================================================

temp_control_mixed_u_ros_cpp_pkg_interfaces__msg__Temperature * get_currentTemp(tcp_tempControl_base_t * self)
{
    return &self->tcp_tempControl_currentTemp_msg;
}

